101:    * The payment schedule.
102:    * <p>
103:    * This is used to define the payment periods.
104:    */
105:   @PropertyDefinition(validate = "notNull")
106:   private final PeriodicSchedule paymentSchedule;
107:   /**
108:    * The fixed coupon rate.
109:    * <p>
110:    * This must be represented in decimal form.
111:    */
112:   @PropertyDefinition(validate = "ArgChecker.notNegative")
113:   private final double fixedRate;
