161:   //-------------------------------------------------------------------------
162:   /**
163:    * Creates an instance of a standardized CDS index.
164:    * 
165:    * @param buySell  buy or sell
166:    * @param cdsIndexId  the CDS index ID
167:    * @param legalEntityIds  the legal entity IDs
168:    * @param currency  the currency
169:    * @param notional  the notional
170:    * @param startDate  the start date
171:    * @param endDate  the end date
172:    * @param calendar  the calendar
173:    * @param paymentFrequency  the payment frequency
174:    * @param fixedRate  the fixed coupon rate
175:    * @return the instance
176:    */
177:   public static CdsIndex of(
178:       BuySell buySell,
179:       StandardId cdsIndexId,
180:       List<StandardId> legalEntityIds,
181:       Currency currency,
182:       double notional,
183:       LocalDate startDate,
184:       LocalDate endDate,
185:       Frequency paymentFrequency,
186:       HolidayCalendarId calendar,
187:       double fixedRate) {
188: 
189:     PeriodicSchedule accrualSchedule = PeriodicSchedule.builder()
190:         .businessDayAdjustment(BusinessDayAdjustment.of(BusinessDayConventions.FOLLOWING, calendar))
191:         .startDate(startDate)
192:         .endDate(endDate)
193:         .startDateBusinessDayAdjustment(BusinessDayAdjustment.NONE)
194:         .endDateBusinessDayAdjustment(BusinessDayAdjustment.NONE)
195:         .frequency(paymentFrequency)
196:         .rollConvention(RollConventions.NONE)
197:         .stubConvention(StubConvention.SMART_INITIAL)
198:         .build();
199:     return new CdsIndex(
200:         buySell,
201:         cdsIndexId,
202:         legalEntityIds,
203:         currency,
204:         notional,
205:         accrualSchedule,
206:         fixedRate,
207:         DayCounts.ACT_360,
208:         PaymentOnDefault.ACCRUED_PREMIUM,
209:         ProtectionStartOfDay.BEGINNING,
210:         DaysAdjustment.ofCalendarDays(1),
211:         DaysAdjustment.ofBusinessDays(3, calendar));
212:   }
